namespace sv_65371fa5d5354edb825ab6c429675e88.Models;

public sealed class Recipe
{
    public required int Id { get; init; }
    public required string Title { get; init; }
    public required string Description { get; init; }
    public required int PrepTimeMinutes { get; init; }
}

using sv_65371fa5d5354edb825ab6c429675e88.Models;

namespace sv_65371fa5d5354edb825ab6c429675e88.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new() { Id = 1, Title = "Margherita Pizza", Description = "Classic pizza with tomato sauce, mozzarella, and fresh basil.", PrepTimeMinutes = 30 },
            new() { Id = 2, Title = "Spaghetti Carbonara", Description = "Creamy pasta with pancetta, egg yolk, and pecorino romano.", PrepTimeMinutes = 25 },
            new() { Id = 3, Title = "Tiramisu", Description = "Layered coffee-soaked ladyfingers with mascarpone cream.", PrepTimeMinutes = 45 },
        },
        [2] = new List<Recipe>
        {
            new() { Id = 4, Title = "Sushi Rolls", Description = "Vinegared rice with fresh fish and vegetables wrapped in nori.", PrepTimeMinutes = 60 },
            new() { Id = 5, Title = "Miso Soup", Description = "Traditional soup with tofu, wakame seaweed, and dashi broth.", PrepTimeMinutes = 15 },
            new() { Id = 6, Title = "Tempura", Description = "Lightly battered and deep-fried shrimp and vegetables.", PrepTimeMinutes = 35 },
        },
        [3] = new List<Recipe>
        {
            new() { Id = 7, Title = "Tacos al Pastor", Description = "Marinated pork tacos with pineapple, cilantro, and onion.", PrepTimeMinutes = 50 },
            new() { Id = 8, Title = "Guacamole", Description = "Fresh avocado dip with lime, cilantro, and jalapeño.", PrepTimeMinutes = 10 },
            new() { Id = 9, Title = "Churros", Description = "Fried dough pastry coated in cinnamon sugar with chocolate sauce.", PrepTimeMinutes = 40 },
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Nav
@using sv_65371fa5d5354edb825ab6c429675e88.Models
@using sv_65371fa5d5354edb825ab6c429675e88.Services

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

<nav style="margin-bottom:1rem">
    <a href="/recipes/1">Italian</a> |
    <a href="/recipes/2">Japanese</a> |
    <a href="/recipes/3">Mexican</a>
</nav>

@if (_errorMessage is not null)
{
    <div role="alert" style="border:1px solid #c00;padding:1rem;border-radius:4px;background:#fff0f0;margin-bottom:1rem">
        <p><strong>⚠ @_errorMessage</strong></p>
        <button @onclick="Retry">Retry</button>
    </div>
}

@if (_recipes is null && _isLoading)
{
    <p><em>Loading recipes…</em></p>
}
else if (_recipes is not null)
{
    @if (_isLoading)
    {
        <p><em>Refreshing…</em></p>
    }

    <table>
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes min</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isLoading;
    private string? _errorMessage;

    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    private IEnumerable<Recipe> DisplayRecipes => Sort?.ToLowerInvariant() switch
    {
        "newest" => _recipes!.OrderByDescending(r => r.Id),
        "popular" => _recipes!.OrderBy(r => r.PrepTimeMinutes),
        _ => _recipes!
    };

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }
        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }
        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);

        _loadedCuisineId = CuisineId;
        _isLoading = true;
        _errorMessage = null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, _loadCts.Token);
            _recipes = results;
        }
        catch (OperationCanceledException) when (_disposeCts.IsCancellationRequested)
        {
            // Component is disposing — stop all work silently.
        }
        catch (OperationCanceledException)
        {
            // Superseded by a newer load — nothing to do.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isLoading = false;
        }
    }

    private Task Retry() => LoadRecipesAsync();

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Dispose();
    }
}

